// Pega os dados do passo anterior
const items = $input.all();

return items.map(item => {
  const ddd = item.json.ddd;

  // Mapas de DDD por região
  const regioes = {
    norte: [68, 96, 92, 97, 91, 93, 94, 69, 95, 63],
    nordeste: [82, 71, 73, 74, 75, 77, 85, 88, 98, 99, 83, 81, 87, 86, 89, 79, 84],
    sudeste: [27, 28, 31, 32, 33, 34, 35, 37, 38, 21, 22, 24, 11, 12, 13, 14, 15, 16, 17, 18, 19],
    sul: [41, 42, 43, 44, 45, 46, 47, 48, 49, 51, 53, 54, 55],
    centro_oeste: [62, 64, 65, 66, 67, 61]
  };

  let regiao = 'nao_identificada';
  let estado = 'nao_identificado';

  // Identifica a região
  for (const [key, values] of Object.entries(regioes)) {
    if (values.includes(ddd)) {
      regiao = key;
      break;
    }
  }

  // Identifica subregião específica para direcionamento
  let subregiao = regiao;

  // São Paulo (11-19)
  if ([11, 12, 13, 14, 15, 16, 17, 18, 19].includes(ddd)) {
    subregiao = 'sao_paulo';
    estado = 'SP';
  }
  // Rio de Janeiro (21, 22, 24)
  else if ([21, 22, 24].includes(ddd)) {
    subregiao = 'rio_de_janeiro';
    estado = 'RJ';
  }
  // Demais estados do Sudeste
  else if ([27, 28].includes(ddd)) {
    subregiao = 'sudeste_outros';
    estado = 'ES';
  }
  else if ([31, 32, 33, 34, 35, 37, 38].includes(ddd)) {
    subregiao = 'sudeste_outros';
    estado = 'MG';
  }
  // Bahia
  else if ([71, 73, 74, 75, 77].includes(ddd)) {
    estado = 'BA';
  }
  // Pernambuco
  else if ([81, 87].includes(ddd)) {
    estado = 'PE';
  }

  // Retorna todos os dados + região identificada
  return {
    json: {
      ...item.json,
      regiao: regiao,
      subregiao: subregiao,
      estado: estado,
      info_regional: {
        ddd: ddd,
        regiao: regiao,
        subregiao: subregiao,
        estado: estado
      }
    }
  };
});

// Pega os dados do passo anterior
const items = $input.all();

return items.map(item => {
  const produto = (item.json.produto || '').toLowerCase();
  const regiao = item.json.regiao;
  const subregiao = item.json.subregiao;
  const ddd = item.json.ddd;

  let executivo = null;
  let email_executivo = null;
  let telefone_executivo = null;
  let motivo_direcionamento = '';

  // ====== GPS (não padaria) ======
  if (produto.includes('gps') && !produto.includes('padaria')) {
    executivo = 'André Augusto';
    email_executivo = 'andre@sucessonoresultado.com.br';
    telefone_executivo = '11958430345';
    motivo_direcionamento = 'Produto GPS';
  }

  // ====== PADARIA ou ALEXY ======
  else if (produto.includes('padaria') || produto.includes('alexy')) {

    // Sudeste (exceto RJ) -> Alex
    if (subregiao === 'sao_paulo' || subregiao === 'sudeste_outros') {
      executivo = 'Alex Araújo';
      email_executivo = 'alex@sucessonoresultado.com.br';
      telefone_executivo = '13996871134';
      motivo_direcionamento = 'Padaria/Alexy - Região Sudeste';
    }
    // Norte e Nordeste -> Gabriela
    else if (regiao === 'norte' || regiao === 'nordeste') {
      executivo = 'Gabriela Câmara';
      email_executivo = 'gabriela@sucessonoresultado.com.br';
      telefone_executivo = '8199092839';
      motivo_direcionamento = 'Padaria/Alexy - Região Norte/Nordeste';
    }
    // Rio de Janeiro e Sul -> Lúcia
    else if (subregiao === 'rio_de_janeiro' || regiao === 'sul') {
      executivo = 'Lúcia Carcerere';
      email_executivo = 'lucia@sucessonoresultado.com.br';
      telefone_executivo = '21981807478';
      motivo_direcionamento = 'Padaria/Alexy - Região RJ/Sul';
    }
    // Centro-Oeste ou não identificado -> Carolina (nacional)
    else {
      executivo = 'Carolina Câmara';
      email_executivo = 'carolina@sucessonoresultado.com.br';
      telefone_executivo = '11960757304';
      motivo_direcionamento = 'Padaria/Alexy - Cobertura Nacional/Centro-Oeste';
    }
  }

  // ====== CAFETERIA ======
  else if (produto.includes('cafe') || produto.includes('cafeteria')) {
    executivo = 'Ana Clara';
    email_executivo = 'anaclaramedeiros@hotmail.com';
    telefone_executivo = '8196747235';
    motivo_direcionamento = 'Segmento Cafeteria';
  }

  // ====== SUPERMERCADO ======
  else if (produto.includes('supermercado') || produto.includes('mercado')) {
    executivo = 'Irelene Guerreiro';
    email_executivo = 'ireleneguerreiro76@hotmail.com';
    telefone_executivo = '19996065250';
    motivo_direcionamento = 'Segmento Supermercado';
  }

  // ====== OUTROS PRODUTOS (exceto padaria) ======
  else {
    // Alterna entre Maria Helena e Helen Monte
    // Usa o timestamp para alternar (par/ímpar)
    const segundoAtual = new Date().getSeconds();

    if (segundoAtual % 2 === 0) {
      executivo = 'Maria Helena';
      email_executivo = 'maria.helena@sucessonoresultado.com.br';
      telefone_executivo = '8199736503';
    } else {
      executivo = 'Helen Monte';
      email_executivo = 'helen@sucessonoresultado.com.br';
      telefone_executivo = '8194969669';
    }
    motivo_direcionamento = 'Outros segmentos (distribuição alternada)';
  }

  // Retorna todos os dados + executivo selecionado
  return {
    json: {
      ...item.json,
      direcionamento: {
        executivo: executivo,
        email_executivo: email_executivo,
        telefone_executivo: telefone_executivo,
        motivo: motivo_direcionamento
      },
      resumo_lead: {
        nome: item.json.nome,
        empresa: item.json.empresa,
        produto: item.json.produto,
        ddd: ddd,
        regiao: regiao,
        executivo_responsavel: executivo
      }
    }
  };
});

// Prepara JSON para WhatsApp com mensagem personalizada
const items = $input.all();

return items.map(item => {
  const lead = item.json;
  const dir = lead.direcionamento;

  // Verifica se os campos necessários existem
  if (!dir || !dir.telefone_executivo) {
    throw new Error('Dados de direcionamento não encontrados');
  }

  // Formata o telefone para WhatsApp
  let telefoneWhats = '';

  if (lead.telefone_limpo) {
    telefoneWhats = lead.telefone_limpo.startsWith('55') 
      ? lead.telefone_limpo 
      : '55' + lead.telefone_limpo;
  } else if (lead.telefone) {
    const telefoneLimpo = lead.telefone.replace(/\D/g, '');
    telefoneWhats = telefoneLimpo.startsWith('55') 
      ? telefoneLimpo 
      : '55' + telefoneLimpo;
  }

  // Pega o primeiro nome do executivo
  const primeiroNome = dir.executivo.split(' ')[0];

  // Monta a mensagem personalizada com o nome do executivo
  const mensagemTexto = `🔥 *NOVO LEAD QUENTINHO!*

Oi ${primeiroNome}! 👋 Aqui é a Rica 🤖

