⚡ *Corre que é seu!*
wa.me/${telefoneWhats}

🤖 Rica`;

  // ====== MENSAGEM PARA MARIA HELENA (notificação de gestão) ======
  const mensagemMariaHelena = `📊 *LEAD DISTRIBUÍDO*

👤 *Lead:* ${lead.nome || 'Não informado'}
🎯 *Produto:* ${lead.produto || 'Não informado'}
📍 *Local:* ${lead.estado || 'BR'} (DDD ${lead.ddd || 'XX'})

➡️ *Direcionado para:* ${dir.executivo}
📋 *Motivo:* ${dir.motivo}

⏰ ${new Date().toLocaleString('pt-BR')}`;

  const whatsappMariaHelena = {
    to: "558199736503",
    text: mensagemMariaHelena
  };

  return {
    json: {
      ...item.json,
      whatsapp_simples: whatsappJSON,
      whatsapp_mensagem_curta: mensagemCurta,
      whatsapp_raw_message: mensagemTexto,
      whatsapp_maria_helena: whatsappMariaHelena,
      numero_executivo_formatado: "55" + telefoneExecutivoLimpo,
      numero_cliente_formatado: telefoneWhats,
      nome_executivo: primeiroNome
    }
  };
});

// Extrai deal_id do contato encontrado
const items = $input.all();

return items.map(item => {
  const contact = item.json.contact || {};
  const deals = contact.deals || [];

  // Pega o deal mais recente com status open
  const openDeals = deals.filter(d => d.status === 'open');
  const deal = openDeals.length > 0 ? openDeals[0] : (deals.length > 0 ? deals[0] : null);

  return {
    json: {
      contact_id: contact.id || null,
      deal_id: deal ? deal.id : null,
      deal_title: deal ? deal.title : null,
      pipeline_name: deal ? deal.pipeline_name : null,
      has_deal: !!deal,
      produto: $('When Executed by Another Workflow').item.json.produto,
      mensagem: $('When Executed by Another Workflow').item.json.mensagem,
      nome: $('When Executed by Another Workflow').item.json.nome,
      executivo: $('Code3').item.json.direcionamento ? $('Code3').item.json.direcionamento.executivo : 'Equipe'
    }
  };
});
